mapper.update:
/* Comu.deleteComuDet */
UPDATE TB_COMU_DET SET
    DEL_YN = 'Y'
WHERE ID = #{id}

mapper.select:
/* Comu.selectCodeDesc */
SELECT CODE_DESC
FROM TB_CODE
WHERE CODE_UPPER = #{codeUpper}
  AND CODE_CD    = #{codeCd}
  AND DEL_YN     = 'N'
LIMIT 1

/* Comu.selectCodeNm */
SELECT CODE_NM
FROM TB_CODE
WHERE CODE_UPPER = #{codeUpper}
  AND CODE_CD    = #{codeCd}
  AND DEL_YN     = 'N'
LIMIT 1
